// // This module decrements the counter value on the rising edge of the clock when up_down is high.
module counter_3bit_updown(
    input clk, 
    input reset, 
    input up_down, 
    output reg [2:0] count);

    always @(posedge clk) begin
        if (reset) 
            count <= 3'b000;
        else if (up_down) 
            count <= count + 1;
        else 
            count <= count - 1;
    end
endmodule
